/**
 * Static entry points for YAML parsing, stringification, comment stripping, semantic equality and the schema factories. Not instantiable.
 *
 * @example
 * ```ts
 * import { Yaml } from "@effected/yaml";
 * import { Effect } from "effect";
 *
 * const program = Effect.gen(function* () {
 *   const value = yield* Yaml.parse("name: Alice\nage: 30");
 *   return value; // { name: "Alice", age: 30 }
 * });
 * ```
 *
 * @public
 */

/**
 * Compare two YAML strings for semantic equality: comments, whitespace, formatting and mapping key order are ignored; sequence order is significant. Malformed input is never equal to anything — parse errors (or duplicate keys) on either side yield `false` rather than comparing recovery-parser artifacts. Pure and total.
 */

/**
 * Compare a YAML string against an existing JavaScript value with the same semantics as {@link Yaml.equals}: malformed `text` yields `false`. Pure and total.
 */

/**
 * Parse a single YAML document into a plain JavaScript value, resolving anchors and aliases. Error-recovery parsing: collects every fatal diagnostic and fails once with the aggregate {@link YamlParseError}. Returns `unknown`, never `any`.
 */

/**
 * Parse a multi-document YAML stream into an array of plain JavaScript values (one per document, in order). Any fatal diagnostic in any document — or a stream-level directive-placement error — fails the whole Effect with the aggregate {@link YamlParseError}.
 */

/**
 * Stringify a plain JavaScript value as YAML. Fails with {@link YamlStringifyError} on circular references.
 */

/**
 * Strip comments from YAML text. Without `replaceCh`, comment characters are removed (line breaks are kept, so line numbers stay stable); with a `replaceCh` (e.g. `" "`), each comment character is replaced instead, keeping all offsets stable. Quote-aware: `#` inside quoted scalars is content, not a comment. Pure and total.
 */

/**
 * The zero-config `Schema<unknown, string>` — `Yaml.fromString()` with default options, pre-bound so the common case needs no memoization discipline.
 */

